import React, { Component } from "react";
import "./Log.css"
import axios from "axios";

import {Link} from "react-router-dom";


export default class Login extends Component {

    state = {

        username:'',
        password:'',
        role:0,
        // token: '',

    };

    // componentDidMount() {
    //     var toke = localStorage.getItem('token');

    //     if (toke) {
    //       this.getUser(toke);
    //     }
    //   }




  handleChange(e){
    this.setState({
     [e.target.name]:e.target.value,
    })
} ;



handleSubmit(e){

    // e.preventDefault();

    // if(e.target.id == 'company'){
    //     this.setState({
    //         role:1
    //     })
    // }else {
    //     this.setState({
    //         role:0
    //     })
    // }
axios.post("http://localhost:5000/login",{ 

    username :this.state.username,
    password:this.state.password,

})
// .then(res => {
//     this.setState({
//       token: res.data.token,
//     });
//     localStorage.setItem('token', res.data.token);
//     this.getUser();
//   })
//   .catch(err => {
//     console.error(err);
//   });


}

    render() {
        return (


            <form onSubmit={this.handleSubmit.bind(this)}>
                <h3>Sign In</h3>

                <div className="form-group">
                    <label>username</label>
                    <input type="text"    value = {this.state.username} name="username" onChange={this.handleChange.bind(this)} className="form-control" placeholder="Enter username" />
                </div>

                <div className="form-group">
                    <label>Password</label>
                    <input type="password"  value = {this.state.password} name="password" onChange={this.handleChange.bind(this)} className="form-control" placeholder="Enter password" />
                </div>

                <div className="form-group">
                    <div className="custom-control custom-checkbox">
                        <input type="checkbox" className="custom-control-input" id="customCheck1" />
                        <label className="custom-control-label" htmlFor="customCheck1">Remember me</label>
                    </div>
                </div>

                {/* <button type="submit"   id="company" className="btn btn-primary btn-block"> Login As A Company </button> */}
                <button type="submit"   id ="volunteer" className="btn btn-primary btn-block">login
                 As A Volunteer</button>

                <p className="forgot-password text-right">

                if you do not have account <a href="/signUp">Register</a>
                </p>
               {/* < Link  href='./../Signin/Login'> </Link> */}
            </form>
        );
    }
}
